import{_ as e,o as r,c as t,ag as i}from"./chunks/framework.ClpDZR9J.js";const h=JSON.parse('{"title":"ECMAScript 规范","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/javascript/23-reference/01-ecmascript-spec.md","filePath":"frontend/javascript/23-reference/01-ecmascript-spec.md","lastUpdated":1773375363000}'),l={name:"frontend/javascript/23-reference/01-ecmascript-spec.md"};function c(o,a,s,n,S,p){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="ecmascript-规范" tabindex="-1">ECMAScript 规范 <a class="header-anchor" href="#ecmascript-规范" aria-label="Permalink to &quot;ECMAScript 规范&quot;">​</a></h1><h2 id="什么是-ecmascript" tabindex="-1">什么是 ECMAScript？ <a class="header-anchor" href="#什么是-ecmascript" aria-label="Permalink to &quot;什么是 ECMAScript？&quot;">​</a></h2><p>ECMAScript 是 JavaScript 的标准化规范，由 ECMA 国际组织维护。</p><h2 id="规范版本" tabindex="-1">规范版本 <a class="header-anchor" href="#规范版本" aria-label="Permalink to &quot;规范版本&quot;">​</a></h2><ul><li>ES1 (1997)：第一个版本</li><li>ES2 (1998)：编辑性变更</li><li>ES3 (1999)：正则表达式、try/catch</li><li>ES4 (废弃)：过于复杂</li><li>ES5 (2009)：严格模式、JSON、数组方法</li><li>ES5.1 (2011)：小幅更新</li><li>ES6 / ES2015：let/const、箭头函数、类、模块、Promise、Symbol、Map/Set、Proxy</li><li>ES7 / ES2016：Array.prototype.includes、指数运算符</li><li>ES8 / ES2017：async/await、Object.values/entries、String.padStart/padEnd</li><li>ES9 / ES2018：对象展开、Promise.finally、异步迭代</li><li>ES10 / ES2019：Array.flat/flatMap、Object.fromEntries、String.trimStart/trimEnd</li><li>ES11 / ES2020：BigInt、可选链、空值合并、Promise.allSettled</li><li>ES12 / ES2021：String.replaceAll、Promise.any、逻辑赋值运算符</li><li>ES13 / ES2022：Array.at、Object.hasOwn、类字段、顶层 await</li><li>ES14 / ES2023：Array.toSorted/toReversed/toSpliced、Hashbang 语法</li><li>ES15 / ES2024：Object.groupBy/Map.groupBy、Promise.withResolvers、Temporal API</li></ul><h2 id="规范文档" tabindex="-1">规范文档 <a class="header-anchor" href="#规范文档" aria-label="Permalink to &quot;规范文档&quot;">​</a></h2><ul><li><a href="https://tc39.es/ecma262/" target="_blank" rel="noreferrer">ECMAScript 规范</a></li><li><a href="https://github.com/tc39/proposals" target="_blank" rel="noreferrer">TC39 提案</a></li></ul><h2 id="tc39-流程" tabindex="-1">TC39 流程 <a class="header-anchor" href="#tc39-流程" aria-label="Permalink to &quot;TC39 流程&quot;">​</a></h2><ol><li>Stage 0：Strawman（稻草人）</li><li>Stage 1：Proposal（提案）</li><li>Stage 2：Draft（草案）</li><li>Stage 3：Candidate（候选）</li><li>Stage 4：Finished（完成）</li></ol><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://tc39.es/ecma262/" target="_blank" rel="noreferrer">ECMAScript 规范</a></li><li><a href="https://tc39.es/" target="_blank" rel="noreferrer">TC39 官网</a></li></ul>',11)])])}const E=e(l,[["render",c]]);export{h as __pageData,E as default};
